pub struct AbstractParametersView { pub max_seqno: nat, pub max_delegations: nat }

impl View for AbstractParameters {
    type V = AbstractParametersView;
    closed spec fn view(&self) -> AbstractParametersView {
        AbstractParametersView { max_seqno: self.max_seqno, max_delegations: self.max_delegations }
    }
}
